mapper.insert:
INSERT INTO daily_sales_summary (stat_date, total_revenue, order_count, visit_count, avg_usage_time) SELECT #{targetDate}, IFNULL(SUM(ts.total_amount), 0), /* 주문 건수: 단순 카운트이므로 서브쿼리 유지 (성능 영향 미미) */ (SELECT COUNT(*) FROM orders WHERE ordered_at >= #{targetDate} AND ordered_at < DATE_ADD(#{targetDate}, INTERVAL 1 DAY) AND status NOT IN ('PENDING', 'CANCELLED')),
/* [핵심] 방문자 수: 초기 인원 + JOIN으로 계산된 추가 인원 수량 */ IFNULL(SUM(ts.initial_guest_cnt + IFNULL(extra.extra_qty, 0)), 0),
IFNULL(AVG(TIMESTAMPDIFF(MINUTE, ts.check_in_time, ts.check_out_time)), 0) FROM table_session ts /* INNER JOIN을 사용해 '인원 추가' 항목만 미리 합산한 파생 테이블을 연결 */ LEFT JOIN ( SELECT o.session_id, SUM(oi.quantity) as extra_qty FROM order_item oi INNER JOIN orders o ON oi.order_id = o.id WHERE oi.menu_name = '인원 추가 (1명)' AND o.status NOT IN ('PENDING', 'CANCELLED') GROUP BY o.session_id ) extra ON ts.id = extra.session_id WHERE ts.check_out_time >= #{targetDate} AND ts.check_out_time < DATE_ADD(#{targetDate}, INTERVAL 1 DAY) AND ts.is_active = FALSE
